import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import ProductCard from '../components/ProductCard';
import { products, categories } from '../api';
import { 
  ArrowRight, 
  Smartphone, 
  Shirt, 
  ShoppingBag, 
  Watch, 
  Home as HomeIcon,
  Star,
  Quote
} from 'lucide-react';

const Home = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const [productsList, setProductsList] = useState([]);
  const [brands, setBrands] = useState([]);
  const [selectedBrand, setSelectedBrand] = useState(searchParams.get('brand') || '');
  const [searchQuery, setSearchQuery] = useState(searchParams.get('name') || '');

  // Mock categories for the redesign
  const categoryTiles = [
    { name: 'Elektronika', icon: <Smartphone size={32} />, color: '#EFF6FF' },
    { name: 'Kiyim-kechak', icon: <Shirt size={32} />, color: '#FEF3C7' },
    { name: 'Oyoq kiyimlar', icon: <ShoppingBag size={32} />, color: '#ECFDF5' },
    { name: 'Aksessuarlar', icon: <Watch size={32} />, color: '#F5F3FF' },
    { name: 'Uy anjomlari', icon: <HomeIcon size={32} />, color: '#FFF1F2' },
  ];

  // Mock reviews
  const reviews = [
    { name: 'Azizbek K.', role: 'Dizayner', text: 'Juda mazmunli va sifatli mahsulotlar. Xizmat ko‘rsatish ham a‘lo darajada!', rating: 5, img: 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=100' },
    { name: 'Malika R.', role: 'Tadbirkor', text: 'Yetkazib berish juda tez. Har safar kutganimdan ham yaxshi natija olaman.', rating: 5, img: 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=100' },
    { name: 'Farhod T.', role: 'Talaba', text: 'Narxlari juda hamyonbop. Sifati esa juda yuqori!', rating: 4, img: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=100' },
  ];

  useEffect(() => {
    const brand = searchParams.get('brand');
    const name = searchParams.get('name');
    setSelectedBrand(brand || '');
    setSearchQuery(name || '');

    const params = {};
    if (brand) params.brand = brand;
    if (name) params.name = name;

    products.getAll(params).then(res => {
      setProductsList(res.data);
      const uniqueBrands = [...new Set(res.data.map(p => p.brand))];
      setBrands(uniqueBrands);
    });
  }, [searchParams]);

  return (
    <div className="home-page">
      {/* Hero Section */}
      <section className="hero" style={{ background: 'white', minHeight: '90vh', display: 'flex', alignItems: 'center', position: 'relative', overflow: 'hidden' }}>
        {/* Background Decorative Elements */}
        <div style={{ position: 'absolute', top: '-10%', right: '-5%', width: '600px', height: '600px', background: 'radial-gradient(circle, rgba(37, 99, 235, 0.08) 0%, transparent 70%)', zIndex: 0 }}></div>
        <div style={{ position: 'absolute', bottom: '10%', left: '5%', width: '400px', height: '400px', background: 'radial-gradient(circle, rgba(124, 58, 237, 0.05) 0%, transparent 70%)', zIndex: 0 }}></div>

        <div className="container hero-grid" style={{ position: 'relative', zIndex: 1, gap: '80px' }}>
          <motion.div 
            className="hero-content"
            initial={{ opacity: 0, x: -60 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 1, ease: "easeOut" }}
          >
            <motion.span 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.3 }}
              style={{ 
                display: 'inline-block', padding: '8px 16px', borderRadius: '100px', background: 'rgba(37, 99, 235, 0.1)', 
                color: 'var(--primary)', fontWeight: 600, fontSize: '14px', marginBottom: '24px' 
              }}
            >
              ✨ ShopSRY Premium Selection 2026
            </motion.span>
            <h1 style={{ fontSize: '72px', lineHeight: 1.1, marginBottom: '24px', fontWeight: 800 }}>
              Kelajak <span className="text-gradient">Texnologiyasi</span> Sizning Qo'lingizda
            </h1>
            <p style={{ fontSize: '20px', color: '#6B7280', marginBottom: '40px', lineHeight: 1.6, maxWidth: '540px' }}>
              Eng sara mahsulotlar, zamonaviy dizayn va sifat uyg'unligi. O'z hayotingizni biz bilan yanada yorqinroq qiling.
            </p>

            <div className="hero-btns" style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
              <Link to="/products" className="btn-wow">
                Xaridni boshlash <ArrowRight size={20} />
              </Link>
              <div className="glass" style={{ padding: '8px 24px', borderRadius: '16px', display: 'flex', alignItems: 'center', gap: '12px', border: '1px solid #eee' }}>
                <div style={{ display: 'flex' }}>
                   {[1,2,3].map(i => <div key={i} style={{ width: '32px', height: '32px', borderRadius: '50%', border: '2px solid white', marginLeft: i > 1 ? '-12px' : 0, background: '#eee' }}></div>)}
                </div>
                <span style={{ fontSize: '14px', fontWeight: 600 }}>10k+ Mijozlar</span>
              </div>
            </div>
          </motion.div>

          <motion.div 
            className="hero-image floating-anim"
            initial={{ opacity: 0, scale: 0.8, x: 60 }}
            animate={{ opacity: 1, scale: 1, x: 0 }}
            transition={{ duration: 1.2, ease: "easeOut" }}
            style={{ position: 'relative' }}
          >
            <div style={{ 
              position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', 
              width: '120%', height: '120%', background: 'radial-gradient(circle, rgba(37, 99, 235, 0.05) 0%, transparent 70%)',
              zIndex: -1
            }}></div>
            <img 
              src="/Users/urinovtolmas/.gemini/antigravity/brain/098e7e58-455e-4165-8414-c1ae521d2e68/premium_tech_hero_product_1774731938570.png" 
              alt="Premium Hero" 
              style={{ width: '100%', filter: 'drop-shadow(0 30px 60px rgba(0,0,0,0.12))' }}
            />
            {/* Float Badge */}
            <motion.div 
               className="glass"
               animate={{ y: [0, -10, 0] }}
               transition={{ duration: 4, repeat: Infinity }}
               style={{ 
                 position: 'absolute', bottom: '10%', left: '-10%', padding: '20px', borderRadius: '24px', 
                 boxShadow: '0 10px 30px rgba(0,0,0,0.05)', display: 'flex', gap: '16px', alignItems: 'center' 
               }}
            >
              <div style={{ width: '48px', height: '48px', borderRadius: '12px', background: 'var(--secondary)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white' }}>
                 <Star size={24} fill="white" />
              </div>
              <div>
                <h4 style={{ margin: 0 }}>4.9 Rating</h4>
                <p style={{ margin: 0, fontSize: '12px', color: '#6B7280' }}>Ishonchli sifat</p>
              </div>
            </motion.div>
          </motion.div>
        </div>
      </section>

      {/* Categories Grid */}
      <section id="categories" className="container section">
        <div style={{ textAlign: 'center', marginBottom: '48px' }}>
          <h4 style={{ color: '#2563EB', fontWeight: 600, letterSpacing: '1px', marginBottom: '12px' }}>INTERAKTIV</h4>
          <h2 className="section-title" style={{ textAlign: 'center' }}>Kategoriyalar Boyicha Izlash</h2>
        </div>
        <div className="category-grid">
          {categoryTiles.map((cat, i) => (
            <motion.div
              key={i}
              className="category-card"
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: i * 0.1 }}
            >
              <div className="category-icon" style={{ backgroundColor: cat.color }}>
                {cat.icon}
              </div>
              <h4 style={{ fontWeight: 600 }}>{cat.name}</h4>
              <Link to="/products" style={{ fontSize: '12px', color: '#6B7280', marginTop: '8px', display: 'block' }}>Ko'proq</Link>
            </motion.div>
          ))}
        </div>
      </section>

      {/* Featured Products */}
      <section className="container section">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '48px' }}>
          <div>
            <h4 style={{ color: '#2563EB', fontWeight: 600, letterSpacing: '1px', marginBottom: '12px' }}>MAXSUS TANLOV</h4>
            <h2 className="section-title" style={{ margin: 0 }}>Yangi yetkazilgan mahsulotlar</h2>
          </div>
          <Link to="/products" style={{ color: '#2563EB', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '8px' }}>
            Hammasini ko'rish <ArrowRight size={16} />
          </Link>
        </div>

        <div className="products-grid">
          {productsList.length > 0 ? (
            productsList.slice(0, 8).map((product, index) => (
              <ProductCard key={product.id} product={product} />
            ))
          ) : (
            <p style={{ textAlign: 'center', gridColumn: '1/-1', color: '#6B7280' }}>Mahsulotlar yuklanmoqda...</p>
          )}
        </div>
      </section>

      {/* Special Offer Section */}
      <section className="container section">
        <motion.div 
          className="special-offer"
          initial={{ opacity: 0, scale: 0.95 }}
          whileInView={{ opacity: 1, scale: 1 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8 }}
        >
          <div className="offer-content">
            <h4 style={{ color: '#F59E0B', fontWeight: 700, marginBottom: '16px' }}>LIMITED TIME OFFER</h4>
            <h2 style={{ fontSize: '42px', marginBottom: '24px' }}>Haftaning eng katta chegirmalari!</h2>
            <p style={{ opacity: 0.8, marginBottom: '32px' }}>
              Faqatgina shu hafta ichida barcha elektronika mahsulotlariga 40% gacha keshbek oling. Fursatni qo'ldan boy bermang!
            </p>
            <div className="timer">
              <div className="time-box"><span>12</span><p>Hours</p></div>
              <div className="time-box"><span>45</span><p>Mins</p></div>
              <div className="time-box"><span>30</span><p>Secs</p></div>
            </div>
            <Link to="/products" className="btn btn-primary" style={{ background: '#F59E0B' }}>
              Chegirmalarni ko'rish
            </Link>
          </div>
          <div className="offer-image" style={{ flex: 1, textAlign: 'center' }}>
            <img 
              src="https://images.unsplash.com/photo-1491933382434-500287f9b54b?w=600" 
              alt="Offer product" 
              style={{ width: '100%', borderRadius: '20px', boxShadow: '0 20px 40px rgba(0,0,0,0.4)' }}
            />
          </div>
        </motion.div>
      </section>

      {/* Reviews Section */}
      <section className="container section">
        <div style={{ textAlign: 'center', marginBottom: '60px' }}>
          <h4 style={{ color: '#2563EB', fontWeight: 600, letterSpacing: '1px', marginBottom: '12px' }}>MIJOZLAR FIKRI</h4>
          <h2 className="section-title">Biz haqimizda nima deyishadi?</h2>
        </div>
        <div className="reviews-grid">
          {reviews.map((review, i) => (
            <motion.div 
              key={i} 
              className="review-card"
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: i * 0.1 }}
            >
              <div style={{ color: '#F59E0B', marginBottom: '16px' }}>
                <Quote size={32} />
              </div>
              <p style={{ fontStyle: 'italic', color: '#4B5563', marginBottom: '24px', minHeight: '80px' }}>
                "{review.text}"
              </p>
              <div className="review-header">
                <img src={review.img} alt={review.name} className="reviewer-img" />
                <div className="reviewer-info">
                  <h4>{review.name}</h4>
                  <p>{review.role}</p>
                  <div style={{ display: 'flex', gap: '2px', marginTop: '4px' }}>
                    {[1, 2, 3, 4, 5].map(star => (
                      <Star key={star} size={12} fill={star <= review.rating ? "#F59E0B" : "none"} color={star <= review.rating ? "#F59E0B" : "#D1D5DB"} />
                    ))}
                  </div>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </section>

      {/* Newsletter Section */}
      <section className="container section">
        <motion.div 
          className="newsletter"
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          viewport={{ once: true }}
          transition={{ duration: 1 }}
        >
          <h2 style={{ fontSize: '32px', marginBottom: '16px' }}>Yangi mahsulotlardan xabardor bo'ling</h2>
          <p style={{ opacity: 0.8 }}>Elektron pochtangizni qoldiring va barcha yangiliklar hamda chegirmalardan birinchilardan bo'lib xabardor bo'ling.</p>
          <form className="newsletter-form" onSubmit={(e) => e.preventDefault()}>
            <input type="email" placeholder="Sizning elektron pochtangiz..." required />
            <button type="submit" className="btn btn-primary" style={{ background: '#111827' }}>Obuna bo'lish</button>
          </form>
        </motion.div>
      </section>
    </div>
  );
};

export default Home;
